    await db.collection("audit_events").insertOne({
      account_id: account._id,
      event: "rescue_workflow_executed",
      detail: status,
      customer_visible: true,
      created_at: nowDate,
    });
  });
}

if (import.meta.url === `file://${process.argv[1]}`) {
  run()
    .then(() => console.log("workflow done"))
    .catch((e) => {
      console.error(e);
      process.exit(1);
    });
}
